var e=[{id:`L2_1`,type:`dialog`,speaker:`TANK_STATE_NULL_CORRUPT`,text:{KOREA:`<color=#ff3636>박멸. 박멸. 더러운 능력을. 박멸하라.</color>`,JPN:`<color=#ff3636>撲滅。撲滅せよ。汚らわしい能力を。撲滅せよ。</color>`,ENG:`<color=#ff3636>EXTERMINATE. EXTERMINATE. EXTERMINATE THE UNCLEAN. EXTERMINATE.</color>`,TWN:`<color=#ff3636>毀滅。毀滅。骯髒的能力。毀滅吧。</color>`},stage:{bg:`LABORATORY_02`,bgm:`THEMA_SHADOW_PALACE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}},sfx:`FX_COMBAT_MECHANIC_RAZANGRIFF_SKILL_START`},{id:`L3_1`,type:`dialog`,speaker:`TANK_STATE_NULL_CORRUPT`,text:{KOREA:`<color=#ff3636>멸망의 주구. 멸망의 징조. 박멸. 박멸.</color>`,JPN:`<color=#ff3636>滅亡の走狗。滅亡の兆候。撲滅。撲滅。</color>`,ENG:`<color=#ff3636>The hounds of the Fall. The signs of Apocalypse. EXTERMINATE. EXTERMINATE.</color>`,TWN:`<color=#ff3636>滅亡的走狗。滅亡的前兆。毀滅吧。</color>`},stage:{bg:`LABORATORY_02`,bgm:`THEMA_SHADOW_PALACE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_ON`,text:{KOREA:`실컷 부쉈는데도 끝도 없이 쏟아져 나오는군. 남들한테 보여 주기 싫은 장소였던 건가.`,JPN:`これだけ壊してやったのにキリがないな。よっぽど他人に知られたくない場所だったのか。`,ENG:`I already smashed a bunch of them but they just keep coming. Looks like someone didn't want this place found.`,TWN:`這怎麼沒完沒了。難道這裡有什麼不能讓人知道的秘密？`},stage:{bg:`LABORATORY_02`,bgm:`THEMA_SHADOW_PALACE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RITA_HORIZON_NULL_ON`,face:`UNIT_HATE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_ON`,text:{KOREA:`할 수 없지. 지하라서 자제하고 있었지만......`,JPN:`しょうがない。地下だからこの手は使いたくなかったんだが……`,ENG:`I guess I have no choice. I wanted to hold back since we're underground...`,TWN:`沒辦法了，在地下本想要控制一下的……`},stage:{bg:`LABORATORY_02`,bgm:`THEMA_SHADOW_PALACE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RITA_HORIZON_NULL_ON`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_ON`,text:{KOREA:`뭣...... 지진인가? 하필 이럴 때?`,JPN:`……地震か？　よりによってこんな時に？`,ENG:`What the... An earthquake? Why now of all times?`,TWN:`什麼……地震嗎？怎麼偏偏這時候？`},stage:{bg:`LABORATORY_02`,bgm:`THEMA_SHADOW_PALACE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RITA_HORIZON_NULL_ON`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_ON`,text:{KOREA:`꼬맹이, 어디 있어!`,JPN:`ガキ、どこだ！`,ENG:`Where are you, kid?!`,TWN:`小鬼，你在哪裡！`},stage:{bg:`LABORATORY_02`,bgm:`THEMA_SHADOW_PALACE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RITA_HORIZON_NULL_ON`,face:`UNIT_SERIOUS`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`잠시만요! 저 여기 있어요!`,JPN:`大丈夫です！　ここにいます！`,ENG:`Wait! I'm right here!`,TWN:`等等！我在這裡！`},stage:{bg:`LABORATORY_02`,bgm:`THEMA_SHADOW_PALACE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_ON`,text:{KOREA:`탈출해야 돼! 길을 열 테니 놓치지 말고 따라와!`,JPN:`脱出するぞ！　道を開くからしっかりついてこい！`,ENG:`We've got to get out of here! I'll open up a path. Try to keep up!`,TWN:`必須出去！我會開闢一條路，別錯過，跟上！`},stage:{bg:`LABORATORY_02`,bgm:`THEMA_SHADOW_PALACE`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`RITA_HORIZON_NULL_ON`,face:`UNIT_SERIOUS`}}}},{id:`L15_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`네, 언니! 안 떨어지고 꼭 붙어 있을게요!`,JPN:`はい！　離れずぴったりくっついて行きますね！`,ENG:`Got it! I'll be right behind you!`,TWN:`是，姐姐！我會緊緊跟上的！`},stage:{bg:`LABORATORY_02`,bgm:`THEMA_SHADOW_PALACE`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RITA_HORIZON_NULL_ON`,face:`UNIT_SERIOUS`}}}},{id:`L16_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_ON`,text:{KOREA:`이딴 상황에 웃으면서 대답하지 마!`,JPN:`こんな状況でよくそんなヘラヘラできるな、お前は。`,ENG:`How can you smile in a situation like this?!`,TWN:`這種情況你還笑得出來！`},stage:{bg:`LABORATORY_02`,bgm:`THEMA_SHADOW_PALACE`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RITA_HORIZON_NULL_ON`,face:`UNIT_IDLE`}}}}];export{e as default};